        $path = $icons[$name]['path'];
        if ($name === 'rclogo') {
            $path = str_replace(
                [
                    'A.56.56 0 00355.17',
                    'A.59.58 86.1 01354.67',
                    'A.76.75 51.3 00200.25',
                    'A.37.36 70.4 01362.72',
                    'A.35.35 0 00100.75',
                    'A3.21 2.84-74.4 0157.11',
                    'A2.62 2.55-6.5 0061.96',
                    'A2.66 2.65-87.7 0068.37',
                    'A1.34 1.31 88.6 0074.48',
                    'A.35.35 0 00300.96',
                    'A1.34 1.31-88.7 00327.42',
                    'A2.66 2.65 87.7 00333.73',
                    'A2.62 2.55 6.5 00340.36',
                    'A3.21 2.84 74.4 01347.07',
                ],
                [
                    'A 0.56 0.56 0 0 0 355.17',
                    'A 0.59 0.58 86.1 0 1 354.67',
                    'A 0.76 0.75 51.3 0 0 200.25',
                    'A 0.37 0.36 70.4 0 1 362.72',
                    'A 0.35 0.35 0 0 0 100.75',
                    'A 3.21 2.84 -74.4 0 1 57.11',
                    'A 2.62 2.55 -6.5 0 0 61.96',
                    'A 2.66 2.65 -87.7 0 0 68.37',
                    'A 1.34 1.31 88.6 0 0 74.48',
                    'A 0.35 0.35 0 0 0 300.96',
                    'A 1.34 1.31 -88.7 0 0 327.42',
                    'A 2.66 2.65 87.7 0 0 333.73',
                    'A 2.62 2.55 6.5 0 0 340.36',
                    'A 3.21 2.84 74.4 0 1 347.07',
                ],
                $path
            );
            $path = preg_replace('/([A-Za-z])/', ' $1 ', $path);
            $path = preg_replace('/(?<![eE])(-)/', ' $1', (string)$path);
            $path = preg_replace('/\s+/', ' ', (string)$path);
        }

        return '<svg width="' . $size . '" height="' . $size . '" xmlns="http://www.w3.org/2000/svg" viewBox="'
            . htmlspecialchars($icons[$name]['viewBox'], ENT_QUOTES, 'UTF-8') . '"' . $classAttr . $attrs . '><path' . $fillAttr . ' d="'
            . htmlspecialchars(trim((string)$path), ENT_QUOTES, 'UTF-8') . '"/></svg>';
    }
}
